@page "/patients"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Patients — VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>🐕 Patients</h1>
    <button class="btn btn-primary" @onclick='() => Nav.NavigateTo("/patients/new")'>+ Register Patient</button>
</div>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Search by pet or owner name…" @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="speciesFilter" @bind:after="Search">
            <option value="">All species</option>
            <option>Dog</option>
            <option>Cat</option>
            <option>Bird</option>
            <option>Rabbit</option>
            <option>Reptile</option>
            <option>Other</option>
        </select>
    </div>
</div>

@if (pets == null)
{
    <p class="text-muted">Loading…</p>
}
else if (pets.Count == 0)
{
    <div class="alert alert-info">No patients found. Register a new patient to get started.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Phone</th><th>Actions</th>
            </tr>
        </thead>
        <tbody>
        @foreach (var pet in pets)
        {
            <tr>
                <td><a href="/patients/@pet.Id">@pet.Name</a></td>
                <td>@pet.Species</td>
                <td>@(pet.Breed ?? "—")</td>
                <td>@pet.Owner.FullName</td>
                <td>@pet.Owner.Phone</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => Nav.NavigateTo($@quot;/patients/{pet.Id}")">View</button>
                    <button class="btn btn-sm btn-outline-success" @onclick="() => Nav.NavigateTo($@quot;/appointments/new?petId={pet.Id}")">Book Appt</button>
                </td>
            </tr>
        }
        </tbody>
    </table>
}

@code {
    private List<Pet>? pets;
    private string searchTerm = "";
    private string speciesFilter = "";

    protected override async Task OnInitializedAsync() => await Search();

    private async Task Search()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Pets.Include(p => p.Owner).AsQueryable();

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLower();
            query = query.Where(p => p.Name.ToLower().Contains(term)
                || p.Owner.FirstName.ToLower().Contains(term)
                || p.Owner.LastName.ToLower().Contains(term));
        }
        if (!string.IsNullOrWhiteSpace(speciesFilter))
            query = query.Where(p => p.Species == speciesFilter);

        pets = await query.OrderBy(p => p.Name).Take(100).ToListAsync();
    }
}

@page "/patients/new"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Register Patient — VetClinic</PageTitle>

<h1 class="mb-4">Register New Patient</h1>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="RegisterPatient">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="card mb-3">
        <div class="card-header"><strong>Owner Information</strong></div>
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Existing Owner</label>
                <select class="form-select" @onchange="OwnerSelected">
                    <option value="">— New owner —</option>
                    @foreach (var o in owners)
                    {
                        <option value="@o.Id">@o.FullName — @o.Phone</option>
                    }
                </select>
            </div>

            @if (selectedOwnerId == 0)
            {
                <div class="row g-3">
                    <div class="col-md-6">
                        <label class="form-label">First Name *</label>
                        <InputText class="form-control" @bind-Value="model.OwnerFirstName" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Last Name *</label>
                        <InputText class="form-control" @bind-Value="model.OwnerLastName" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Phone *</label>
                        <InputText class="form-control" @bind-Value="model.OwnerPhone" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="model.OwnerEmail" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Address</label>
                        <InputText class="form-control" @bind-Value="model.OwnerAddress" />
                    </div>
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header"><strong>Pet Information</strong></div>
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-4">
                    <label class="form-label">Name *</label>
                    <InputText class="form-control" @bind-Value="model.PetName" />
                </div>
                <div class="col-md-4">
                    <label class="form-label">Species *</label>
                    <InputSelect class="form-select" @bind-Value="model.Species">
                        <option value="">Select…</option>
                        <option>Dog</option>
                        <option>Cat</option>
                        <option>Bird</option>
                        <option>Rabbit</option>
                        <option>Reptile</option>
                        <option>Other</option>
                    </InputSelect>
                </div>
                <div class="col-md-4">
                    <label class="form-label">Breed</label>
                    <InputText class="form-control" @bind-Value="model.Breed" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Date of Birth</label>
                    <InputDate class="form-control" @bind-Value="model.DateOfBirth" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Weight (kg)</label>
                    <InputNumber class="form-control" @bind-Value="model.WeightKg" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Sex</label>
                    <InputSelect class="form-select" @bind-Value="model.Sex">
                        <option value="">Select…</option>
                        <option>Male</option>
                        <option>Female</option>
                        <option>Neutered Male</option>
                        <option>Spayed Female</option>
                    </InputSelect>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Microchip ID</label>
                    <InputText class="form-control" @bind-Value="model.MicrochipId" />
                </div>
                <div class="col-12">
                    <label class="form-label">Notes</label>
                    <InputTextArea class="form-control" @bind-Value="model.Notes" rows="2" />
                </div>
            </div>
        </div>
    </div>

    <div class="d-flex gap-2">
        <button type="submit" class="btn btn-primary" disabled="@saving">
            @(saving ? "Saving…" : "Register Patient")
        </button>
        <button type="button" class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("/patients")'>Cancel</button>
    </div>
</EditForm>

@code {
    private PatientFormModel model = new();
    private List<Owner> owners = [];
    private int selectedOwnerId;
    private bool saving;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        owners = await db.Owners.OrderBy(o => o.LastName).ThenBy(o => o.FirstName).ToListAsync();
    }

    private void OwnerSelected(ChangeEventArgs e)
    {
        selectedOwnerId = int.TryParse(e.Value?.ToString(), out var id) ? id : 0;
    }

    private async Task HandleSubmit()
    {
        saving = true;
        errorMessage = null;
        try
        {
            await using var db = await DbFactory.CreateDbContextAsync();

            Owner owner;
            if (selectedOwnerId > 0)
            {
                owner = await db.Owners.FindAsync(selectedOwnerId)
                    ?? throw new InvalidOperationException("Owner not found");
            }
            else
            {
                if (string.IsNullOrWhiteSpace(model.OwnerFirstName) || string.IsNullOrWhiteSpace(model.OwnerLastName) || string.IsNullOrWhiteSpace(model.OwnerPhone))
                {
                    errorMessage = "Owner first name, last name, and phone are required.";
                    return;
                }
                owner = new Owner
                {
                    FirstName = model.OwnerFirstName!.Trim(),
                    LastName = model.OwnerLastName!.Trim(),
                    Phone = model.OwnerPhone!.Trim(),
                    Email = model.OwnerEmail?.Trim(),
                    Address = model.OwnerAddress?.Trim()
                };
                db.Owners.Add(owner);
            }

            if (string.IsNullOrWhiteSpace(model.PetName) || string.IsNullOrWhiteSpace(model.Species))
            {
                errorMessage = "Pet name and species are required.";
                return;
            }

            var pet = new Pet
            {
                Name = model.PetName!.Trim(),
                Species = model.Species!,
                Breed = model.Breed?.Trim(),
                DateOfBirth = model.DateOfBirth,
                WeightKg = model.WeightKg,
                Sex = model.Sex,
                MicrochipId = model.MicrochipId?.Trim(),
                Notes = model.Notes?.Trim(),
                Owner = owner
            };
            db.Pets.Add(pet);
            await db.SaveChangesAsync();

            Nav.NavigateTo($"/patients/{pet.Id}");
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            saving = false;
        }
    }

    private class PatientFormModel
    {
        public string? OwnerFirstName { get; set; }
        public string? OwnerLastName { get; set; }
        public string? OwnerPhone { get; set; }
        public string? OwnerEmail { get; set; }
        public string? OwnerAddress { get; set; }

        [Required] public string? PetName { get; set; }
        [Required] public string? Species { get; set; }
        public string? Breed { get; set; }
        public DateOnly? DateOfBirth { get; set; }
        public decimal? WeightKg { get; set; }
        public string? Sex { get; set; }
        public string? MicrochipId { get; set; }
        public string? Notes { get; set; }
    }
}

