    <h1>@pet.Name <small class="text-muted">(@pet.Species)</small></h1>
    <div class="d-flex gap-2">
        <button class="btn btn-success" @onclick="() => Nav.NavigateTo($@quot;/appointments/new?petId={pet.Id}")">Schedule Appointment</button>
