@code {
    private List<Pet>? pets;
    private string searchTerm = "";
    private string speciesFilter = "";

    protected override async Task OnInitializedAsync() => await Search();

    private async Task Search()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Pets.Include(p => p.Owner).AsQueryable();

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLower();
            query = query.Where(p => p.Name.ToLower().Contains(term)
                || p.Owner.FirstName.ToLower().Contains(term)
                || p.Owner.LastName.ToLower().Contains(term));
        }
        if (!string.IsNullOrWhiteSpace(speciesFilter))
            query = query.Where(p => p.Species == speciesFilter);

        pets = await query.OrderBy(p => p.Name).Take(100).ToListAsync();
    }
}

