@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private List<Treatment> treatments = [];
    private List<Appointment> appointments = [];
    private Treatment newTreatment = new();
    private string activeTab = "details";
    private string? successMessage;

    // Keep a separate context alive for the editable entity
    private ApplicationDbContext? editDb;

    protected override async Task OnInitializedAsync()
    {
        editDb = await DbFactory.CreateDbContextAsync();
        pet = await editDb.Pets.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == Id);
        if (pet == null) return;
        await LoadRelated();
        newTreatment = new Treatment { PetId = Id, Date = DateTime.UtcNow };
    }

    private async Task LoadRelated()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        treatments = await db.Treatments.Where(t => t.PetId == Id).OrderByDescending(t => t.Date).ToListAsync();
        appointments = await db.Appointments.Where(a => a.PetId == Id).OrderByDescending(a => a.StartTime).ToListAsync();
    }

    private async Task SavePetDetails()
    {
        if (editDb == null || pet == null) return;
        await editDb.SaveChangesAsync();
        successMessage = "Pet details saved.";
    }

    private async Task SaveOwnerDetails()
    {
        if (editDb == null || pet == null) return;
        await editDb.SaveChangesAsync();
        successMessage = "Owner details saved.";
    }

    private async Task AddTreatment()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        newTreatment.PetId = Id;
        db.Treatments.Add(newTreatment);
        await db.SaveChangesAsync();
        await LoadRelated();
        newTreatment = new Treatment { PetId = Id, Date = DateTime.UtcNow };
        activeTab = "history";
        successMessage = "Treatment note added.";
    }

    private string StatusColor(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.CheckedIn => "info",
        AppointmentStatus.InProgress => "warning",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        AppointmentStatus.NoShow => "danger",
        _ => "secondary"
    };

    public void Dispose() => editDb?.Dispose();
}

