@page "/appointments"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Appointments — VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>📅 Appointments</h1>
    <button class="btn btn-primary" @onclick='() => Nav.NavigateTo("/appointments/new")'>+ New Appointment</button>
</div>

<div class="row mb-3">
    <div class="col-md-3">
        <label class="form-label">Week of</label>
        <input type="date" class="form-control" @bind="weekStart" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-3">
        <label class="form-label">Status</label>
        <select class="form-select" @bind="statusFilter" @bind:after="LoadAppointments">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<AppointmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <label class="form-label">Veterinarian</label>
        <input type="text" class="form-control" placeholder="Filter by vet…" @bind="vetFilter" @bind:event="oninput" @bind:after="LoadAppointments" />
    </div>
</div>

@if (!string.IsNullOrEmpty(successMessage))
{
    <div class="alert alert-success alert-dismissible">@successMessage <button type="button" class="btn-close" @onclick="() => successMessage = null"></button></div>
}

<div class="row">
    @for (int d = 0; d < 7; d++)
    {
        var day = weekStart.AddDays(d);
        var dayAppts = appointments.Where(a => a.StartTime.Date == day).ToList();
        var isToday = day == DateTime.Today;

        <div class="col-12 mb-3">
            <div class="card @(isToday ? "border-primary" : "")">
                <div class="card-header @(isToday ? "bg-primary text-white" : "")">
                    <strong>@day.ToString("dddd, MMM dd")</strong>
                    <span class="badge @(isToday ? "bg-light text-dark" : "bg-secondary") ms-2">@dayAppts.Count appointments</span>
                </div>
                @if (dayAppts.Count > 0)
                {
                    <table class="table table-sm mb-0">
                        <thead><tr><th style="width:120px">Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Vet</th><th>Status</th><th>Actions</th></tr></thead>
                        <tbody>
                        @foreach (var apt in dayAppts)
                        {
                            <tr>
                                <td>@apt.StartTime.ToLocalTime().ToString("h:mm tt")</td>
                                <td><a href="/patients/@apt.Pet.Id">@apt.Pet.Name</a></td>
                                <td>@apt.Pet.Owner.FullName</td>
                                <td>@apt.Reason</td>
                                <td>@(apt.Veterinarian ?? "—")</td>
                                <td><span class="badge bg-@StatusColor(apt.Status)">@apt.Status</span></td>
                                <td>
                                    @if (apt.Status == AppointmentStatus.Scheduled)
                                    {
                                        <div class="btn-group btn-group-sm">
                                            <button class="btn btn-outline-info" @onclick="() => CheckIn(apt)">Check In</button>
                                            <button class="btn btn-outline-warning" @onclick="() => StartEdit(apt)">Reschedule</button>
                                            <button class="btn btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                                        </div>
                                    }
                                    else if (apt.Status == AppointmentStatus.CheckedIn)
                                    {
                                        <button class="btn btn-sm btn-outline-warning" @onclick="() => StartProgress(apt)">Start</button>
                                    }
                                    else if (apt.Status == AppointmentStatus.InProgress)
                                    {
                                        <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                                    }
                                </td>
                            </tr>
                        }
                        </tbody>
                    </table>
                }
            </div>
        </div>
    }
</div>

@if (editingAppointment != null)
{
    <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Reschedule Appointment</h5>
                    <button type="button" class="btn-close" @onclick="() => editingAppointment = null"></button>
                </div>
                <div class="modal-body">
                    <div class="mb-3">
                        <label class="form-label">New Date & Time</label>
                        <input type="datetime-local" class="form-control" @bind="rescheduleTime" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Veterinarian</label>
                        <input type="text" class="form-control" @bind="editingAppointment.Veterinarian" />
                    </div>
