                    <button class="btn btn-primary" @onclick="SaveReschedule">Save</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
    private string statusFilter = "";
    private string vetFilter = "";
    private List<Appointment> appointments = [];
    private Appointment? editingAppointment;
    private DateTime rescheduleTime;
    private string? rescheduleError;
    private string? successMessage;

    protected override async Task OnInitializedAsync() => await LoadAppointments();

    private async Task LoadAppointments()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var weekEnd = weekStart.AddDays(7);
        var query = db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd);

        if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<AppointmentStatus>(statusFilter, out var status))
            query = query.Where(a => a.Status == status);
        if (!string.IsNullOrWhiteSpace(vetFilter))
            query = query.Where(a => a.Veterinarian != null && a.Veterinarian.ToLower().Contains(vetFilter.ToLower()));

        appointments = await query.OrderBy(a => a.StartTime).ToListAsync();
    }

    private async Task CheckIn(Appointment apt) => await UpdateStatus(apt, AppointmentStatus.CheckedIn, "Checked in.");
    private async Task StartProgress(Appointment apt) => await UpdateStatus(apt, AppointmentStatus.InProgress, "In progress.");
    private async Task Complete(Appointment apt) => await UpdateStatus(apt, AppointmentStatus.Completed, "Completed.");
    private async Task Cancel(Appointment apt) => await UpdateStatus(apt, AppointmentStatus.Cancelled, "Cancelled.");

    private async Task UpdateStatus(Appointment apt, AppointmentStatus status, string msg)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity == null) return;
        entity.Status = status;
        await db.SaveChangesAsync();
        successMessage = $"Appointment {msg}";
        await LoadAppointments();
    }

    private void StartEdit(Appointment apt)
    {
        editingAppointment = apt;
        rescheduleTime = apt.StartTime.ToLocalTime();
        rescheduleError = null;
    }

    private async Task SaveReschedule()
    {
        if (editingAppointment == null) return;
        if (rescheduleTime < DateTime.Now)
        {
            rescheduleError = "Cannot schedule in the past.";
            return;
        }

        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(editingAppointment.Id);
        if (entity == null) return;

        var newStart = rescheduleTime.ToUniversalTime();
        var newEnd = newStart.AddMinutes((entity.EndTime - entity.StartTime).TotalMinutes);

        // Check conflicts
        var hasConflict = await db.Appointments.AnyAsync(a =>
            a.Id != entity.Id &&
            a.Status != AppointmentStatus.Cancelled &&
            a.Veterinarian == editingAppointment.Veterinarian &&
            a.StartTime < newEnd && a.EndTime > newStart);

        if (hasConflict)
        {
            rescheduleError = "This time slot conflicts with another appointment for the same veterinarian.";
            return;
        }

        entity.StartTime = newStart;
        entity.EndTime = newEnd;
        entity.Veterinarian = editingAppointment.Veterinarian;
        entity.Notes = editingAppointment.Notes;
        await db.SaveChangesAsync();

        editingAppointment = null;
        successMessage = "Appointment rescheduled.";
        await LoadAppointments();
    }

    private string StatusColor(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.CheckedIn => "info",
        AppointmentStatus.InProgress => "warning",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        AppointmentStatus.NoShow => "danger",
        _ => "secondary"
    };
}

@page "/appointments/new"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>New Appointment — VetClinic</PageTitle>

<h1 class="mb-4">Schedule Appointment</h1>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row">
    <div class="col-md-7">
        <div class="card">
            <div class="card-body">
                <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="NewAppointment">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />

                    <div class="mb-3">
                        <label class="form-label">Patient *</label>
                        <select class="form-select" @bind="model.PetId" @bind:after="OnPetChanged">
                            <option value="0">Select a patient…</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Species) — Owner: @pet.Owner.FullName</option>
                            }
                        </select>
                    </div>

                    <div class="row g-3 mb-3">
                        <div class="col-md-6">
                            <label class="form-label">Date *</label>
                            <InputDate class="form-control" @bind-Value="model.Date" @bind-Value:after="CheckAvailability" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Time *</label>
                            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                                <option value="">Select a time…</option>
                                @foreach (var slot in availableSlots)
                                {
                                    <option value="@slot.ToString("HH:mm")">@slot.ToString("h:mm tt") @(bookedSlots.Contains(slot.ToString("HH:mm")) ? "⚠️ Busy" : "✅ Available")</option>
                                }
                            </InputSelect>
                        </div>
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Duration</label>
                        <InputSelect class="form-select" @bind-Value="model.DurationMinutes">
                            <option value="15">15 minutes</option>
                            <option value="30">30 minutes</option>
                            <option value="45">45 minutes</option>
                            <option value="60">60 minutes</option>
                        </InputSelect>
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Reason *</label>
                        <InputText class="form-control" @bind-Value="model.Reason" placeholder="e.g. Annual checkup, vaccination, dental cleaning…" />
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="model.Veterinarian" @bind-Value:after="CheckAvailability" />
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="model.Notes" rows="2" />
                    </div>

                    <div class="d-flex gap-2">
                        <button type="submit" class="btn btn-primary" disabled="@saving">@(saving ? "Scheduling…" : "Schedule Appointment")</button>
                        <button type="button" class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("/appointments")'>Cancel</button>
                    </div>
                </EditForm>
            </div>
        </div>
    </div>

    <div class="col-md-5">
        <div class="card">
            <div class="card-header"><strong>Availability for @model.Date.ToString("MMM dd, yyyy")</strong></div>
            <div class="card-body p-0">
                @if (dayAppointments.Count == 0)
                {
                    <p class="text-success p-3 mb-0">All time slots are available.</p>
                }
                else
                {
                    <table class="table table-sm mb-0">
                        <thead><tr><th>Time</th><th>Pet</th><th>Vet</th><th>Status</th></tr></thead>
                        <tbody>
                        @foreach (var apt in dayAppointments)
                        {
                            <tr>
                                <td>@apt.StartTime.ToLocalTime().ToString("h:mm tt") – @apt.EndTime.ToLocalTime().ToString("h:mm tt")</td>
                                <td>@apt.Pet.Name</td>
                                <td>@(apt.Veterinarian ?? "—")</td>
                                <td><span class="badge bg-@(apt.Status == AppointmentStatus.Cancelled ? "secondary" : "primary")">@apt.Status</span></td>
                            </tr>
                        }
                        </tbody>
                    </table>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [SupplyParameterFromQuery] public int? PetId { get; set; }

    private AppointmentFormModel model = new();
    private List<Pet> pets = [];
    private List<Appointment> dayAppointments = [];
    private List<DateTime> availableSlots = [];
    private HashSet<string> bookedSlots = [];
    private bool saving;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        model.Date = DateOnly.FromDateTime(DateTime.Today);
        model.DurationMinutes = 30;
        if (PetId.HasValue) model.PetId = PetId.Value;
        await CheckAvailability();
    }

    private async Task OnPetChanged() => await CheckAvailability();

    private async Task CheckAvailability()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var date = model.Date.ToDateTime(TimeOnly.MinValue);
        var nextDate = date.AddDays(1);

        dayAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= date && a.StartTime < nextDate && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        // Generate slots from 8 AM to 6 PM
        availableSlots = [];
        bookedSlots = [];
        for (var hour = 8; hour < 18; hour++)
        {
            for (var min = 0; min < 60; min += 30)
            {
                var slot = new DateTime(date.Year, date.Month, date.Day, hour, min, 0);
                availableSlots.Add(slot);

                var slotEnd = slot.AddMinutes(model.DurationMinutes);
                var hasConflict = dayAppointments.Any(a =>
                    (string.IsNullOrEmpty(model.Veterinarian) || a.Veterinarian == model.Veterinarian) &&
                    a.StartTime.ToLocalTime() < slotEnd && a.EndTime.ToLocalTime() > slot);
                if (hasConflict)
                    bookedSlots.Add(slot.ToString("HH:mm"));
            }
        }
    }

    private async Task HandleSubmit()
    {
        saving = true;
        errorMessage = null;
        try
        {
            if (model.PetId == 0)
            {
                errorMessage = "Please select a patient.";
                return;
            }
            if (string.IsNullOrWhiteSpace(model.TimeSlot))
            {
                errorMessage = "Please select a time slot.";
                return;
            }

            var time = TimeOnly.Parse(model.TimeSlot);
            var startLocal = model.Date.ToDateTime(time);
            var startUtc = startLocal.ToUniversalTime();
            var endUtc = startUtc.AddMinutes(model.DurationMinutes);

            await using var db = await DbFactory.CreateDbContextAsync();

            // Final conflict check
            if (!string.IsNullOrWhiteSpace(model.Veterinarian))
            {
                var hasConflict = await db.Appointments.AnyAsync(a =>
                    a.Status != AppointmentStatus.Cancelled &&
                    a.Veterinarian == model.Veterinarian &&
                    a.StartTime < endUtc && a.EndTime > startUtc);
                if (hasConflict)
                {
                    errorMessage = "This time slot conflicts with another appointment for the selected veterinarian.";
                    return;
                }
            }

            var appointment = new Appointment
            {
                PetId = model.PetId,
                StartTime = startUtc,
                EndTime = endUtc,
                Reason = model.Reason!,
                Veterinarian = model.Veterinarian,
                Notes = model.Notes,
                Status = AppointmentStatus.Scheduled
            };

            db.Appointments.Add(appointment);
            await db.SaveChangesAsync();
            Nav.NavigateTo("/appointments");
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            saving = false;
        }
    }

    private class AppointmentFormModel
    {
        public int PetId { get; set; }
        public DateOnly Date { get; set; }
        public string? TimeSlot { get; set; }
        public int DurationMinutes { get; set; } = 30;
        [Required] public string? Reason { get; set; }
        public string? Veterinarian { get; set; }
        public string? Notes { get; set; }
    }
}

@page "/billing"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Billing — VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>🧾 Billing</h1>
    <button class="btn btn-primary" @onclick='() => Nav.NavigateTo("/billing/new-invoice")'>+ New Invoice</button>
</div>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item"><button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => { activeTab = "invoices"; }'>Invoices</button></li>
    <li class="nav-item"><button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => { activeTab = "payments"; LoadPayments(); }'>Payment History</button></li>
</ul>

@if (!string.IsNullOrEmpty(successMessage))
{
    <div class="alert alert-success alert-dismissible">@successMessage <button type="button" class="btn-close" @onclick="() => successMessage = null"></button></div>
}

@if (activeTab == "invoices")
{
    <div class="row mb-3">
        <div class="col-md-3">
            <select class="form-select" @bind="invoiceStatusFilter" @bind:after="LoadInvoices">
                <option value="">All statuses</option>
                @foreach (var s in Enum.GetValues<InvoiceStatus>())
                {
                    <option value="@s">@s</option>
                }
            </select>
        </div>
        <div class="col-md-3">
            <input type="text" class="form-control" placeholder="Search by invoice # or owner…" @bind="invoiceSearch" @bind:event="oninput" @bind:after="LoadInvoices" />
        </div>
    </div>

    <table class="table table-striped table-hover">
        <thead><tr><th>Invoice #</th><th>Date</th><th>Pet</th><th>Owner</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr></thead>
        <tbody>
        @foreach (var inv in invoices)
        {
            <tr>
                <td>@inv.InvoiceNumber</td>
                <td>@inv.IssuedDate.ToLocalTime().ToString("yyyy-MM-dd")</td>
                <td>@inv.Pet.Name</td>
                <td>@inv.Owner.FullName</td>
                <td>$@inv.Total.ToString("N2")</td>
                <td>$@inv.AmountPaid.ToString("N2")</td>
                <td class="@(inv.Balance > 0 ? "text-danger fw-bold" : "text-success")">$@inv.Balance.ToString("N2")</td>
                <td><span class="badge bg-@InvoiceStatusColor(inv.Status)">@inv.Status</span></td>
                <td>
                    <div class="btn-group btn-group-sm">
                        <button class="btn btn-outline-primary" @onclick="() => ViewInvoice(inv)">View</button>
                        @if (inv.Status == InvoiceStatus.Issued || inv.Status == InvoiceStatus.PartiallyPaid || inv.Status == InvoiceStatus.Overdue)
                        {
                            <button class="btn btn-outline-success" @onclick="() => StartPayment(inv)">Pay</button>
                        }
                    </div>
                </td>
            </tr>
        }
        </tbody>
    </table>
    if (invoices.Count == 0)
    {
        <div class="alert alert-info">No invoices found.</div>
    }
}
else
{
    <table class="table table-striped">
        <thead><tr><th>Date</th><th>Invoice #</th><th>Owner</th><th>Amount</th><th>Method</th><th>Status</th><th>Reference</th></tr></thead>
        <tbody>
        @foreach (var p in payments)
        {
            <tr>
                <td>@p.Date.ToLocalTime().ToString("yyyy-MM-dd h:mm tt")</td>
                <td>@p.Invoice.InvoiceNumber</td>
                <td>@p.Invoice.Owner.FullName</td>
                <td>$@p.Amount.ToString("N2")</td>
                <td>@p.Method</td>
                <td><span class="badge bg-@(p.Status == PaymentStatus.Completed ? "success" : p.Status == PaymentStatus.Refunded ? "warning" : "danger")">@p.Status</span></td>
                <td>@(p.Reference ?? "—")</td>
            </tr>
        }
        </tbody>
    </table>
    if (payments.Count == 0)
    {
        <div class="alert alert-info">No payment records.</div>
    }
}

@* View Invoice Modal *@
@if (viewingInvoice != null)
{
    <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog modal-lg">
