                        <div class="col-6 text-end"><strong>Date:</strong> @viewingInvoice.IssuedDate.ToLocalTime().ToString("yyyy-MM-dd")<br/><strong>Status:</strong> <span class="badge bg-@InvoiceStatusColor(viewingInvoice.Status)">@viewingInvoice.Status</span></div>
