@* Payment Modal *@
@if (payingInvoice != null)
{
    <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Process Payment — @payingInvoice.InvoiceNumber</h5>
                    <button type="button" class="btn-close" @onclick="() => payingInvoice = null"></button>
                </div>
                <div class="modal-body">
                    <p>Balance due: <strong class="text-danger">$@payingInvoice.Balance.ToString("N2")</strong></p>
                    <div class="mb-3">
                        <label class="form-label">Amount</label>
                        <input type="number" class="form-control" step="0.01" @bind="paymentAmount" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Payment Method</label>
                        <select class="form-select" @bind="paymentMethod">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </select>
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Reference</label>
                        <input type="text" class="form-control" @bind="paymentReference" placeholder="Card last 4, check #, etc." />
                    </div>
                    @if (!string.IsNullOrEmpty(paymentError))
                    {
                        <div class="alert alert-danger">@paymentError</div>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="() => payingInvoice = null">Cancel</button>
                    <button class="btn btn-success" @onclick="ProcessPayment">Process Payment</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private string invoiceStatusFilter = "";
    private string invoiceSearch = "";
    private List<Invoice> invoices = [];
    private List<Payment> payments = [];
    private Invoice? viewingInvoice;
    private Invoice? payingInvoice;
    private decimal paymentAmount;
    private PaymentMethod paymentMethod = PaymentMethod.Cash;
    private string? paymentReference;
    private string? paymentError;
    private string? successMessage;

    protected override async Task OnInitializedAsync() => await LoadInvoices();

    private async Task LoadInvoices()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();

        if (!string.IsNullOrWhiteSpace(invoiceStatusFilter) && Enum.TryParse<InvoiceStatus>(invoiceStatusFilter, out var status))
            query = query.Where(i => i.Status == status);
        if (!string.IsNullOrWhiteSpace(invoiceSearch))
        {
            var term = invoiceSearch.Trim().ToLower();
            query = query.Where(i => i.InvoiceNumber.ToLower().Contains(term)
                || i.Owner.FirstName.ToLower().Contains(term)
                || i.Owner.LastName.ToLower().Contains(term));
        }

        invoices = await query.OrderByDescending(i => i.IssuedDate).Take(100).ToListAsync();
    }

    private async Task LoadPayments()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        payments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.Date)
            .Take(100)
            .ToListAsync();
    }

    private void ViewInvoice(Invoice inv) => viewingInvoice = inv;

    private void StartPayment(Invoice inv)
    {
        payingInvoice = inv;
        paymentAmount = inv.Balance;
        paymentMethod = PaymentMethod.Cash;
        paymentReference = null;
        paymentError = null;
    }

    private async Task ProcessPayment()
    {
        if (payingInvoice == null) return;
        if (paymentAmount <= 0)
        {
            paymentError = "Amount must be greater than zero.";
            return;
        }
        if (paymentAmount > payingInvoice.Balance)
        {
            paymentError = "Amount exceeds the outstanding balance.";
            return;
        }

        await using var db = await DbFactory.CreateDbContextAsync();
        var payment = new Payment
        {
            InvoiceId = payingInvoice.Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            Reference = paymentReference,
            Date = DateTime.UtcNow,
            Status = PaymentStatus.Completed
        };
        db.Payments.Add(payment);

        var invoice = await db.Invoices.Include(i => i.Items).Include(i => i.Payments).FirstAsync(i => i.Id == payingInvoice.Id);
        // Reload to recalc after adding payment
        invoice.Payments.Add(payment);
        var newBalance = invoice.Total - invoice.Payments.Where(p => p.Status == PaymentStatus.Completed).Sum(p => p.Amount);
        invoice.Status = newBalance <= 0 ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;

        await db.SaveChangesAsync();
        payingInvoice = null;
        successMessage = $"Payment of ${paymentAmount:N2} processed successfully.";
        await LoadInvoices();
    }

    private string InvoiceStatusColor(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Draft => "secondary",
        InvoiceStatus.Issued => "primary",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "warning",
        InvoiceStatus.Overdue => "danger",
        InvoiceStatus.Cancelled => "dark",
        _ => "secondary"
    };
}

