                    <button type="button" class="btn-close" @onclick="() => editingAppointment = null"></button>
                </div>
                <div class="modal-body">
                    <div class="mb-3">
                        <label class="form-label">New Date & Time</label>
                        <input type="datetime-local" class="form-control" @bind="rescheduleTime" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Veterinarian</label>
                        <input type="text" class="form-control" @bind="editingAppointment.Veterinarian" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Notes</label>
                        <textarea class="form-control" @bind="editingAppointment.Notes" rows="2"></textarea>
                    </div>
                    @if (!string.IsNullOrEmpty(rescheduleError))
                    {
                        <div class="alert alert-danger">@rescheduleError</div>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="() => editingAppointment = null">Cancel</button>
                    <button class="btn btn-primary" @onclick="SaveReschedule">Save</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek);
    private string statusFilter = "";
    private string vetFilter = "";
    private List<Appointment> appointments = [];
    private Appointment? editingAppointment;
    private DateTime rescheduleTime;
    private string? rescheduleError;
    private string? successMessage;

    protected override async Task OnInitializedAsync() => await LoadAppointments();

    private async Task LoadAppointments()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var weekEnd = weekStart.AddDays(7);
        var query = db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= weekStart && a.StartTime < weekEnd);

        if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<AppointmentStatus>(statusFilter, out var status))
            query = query.Where(a => a.Status == status);
        if (!string.IsNullOrWhiteSpace(vetFilter))
            query = query.Where(a => a.Veterinarian != null && a.Veterinarian.ToLower().Contains(vetFilter.ToLower()));

        appointments = await query.OrderBy(a => a.StartTime).ToListAsync();
    }

    private async Task CheckIn(Appointment apt) => await UpdateStatus(apt, AppointmentStatus.CheckedIn, "Checked in.");
    private async Task StartProgress(Appointment apt) => await UpdateStatus(apt, AppointmentStatus.InProgress, "In progress.");
    private async Task Complete(Appointment apt) => await UpdateStatus(apt, AppointmentStatus.Completed, "Completed.");
    private async Task Cancel(Appointment apt) => await UpdateStatus(apt, AppointmentStatus.Cancelled, "Cancelled.");

    private async Task UpdateStatus(Appointment apt, AppointmentStatus status, string msg)
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(apt.Id);
        if (entity == null) return;
        entity.Status = status;
        await db.SaveChangesAsync();
        successMessage = $"Appointment {msg}";
        await LoadAppointments();
    }

    private void StartEdit(Appointment apt)
    {
        editingAppointment = apt;
        rescheduleTime = apt.StartTime.ToLocalTime();
        rescheduleError = null;
    }

    private async Task SaveReschedule()
    {
        if (editingAppointment == null) return;
        if (rescheduleTime < DateTime.Now)
        {
            rescheduleError = "Cannot schedule in the past.";
            return;
        }

        await using var db = await DbFactory.CreateDbContextAsync();
        var entity = await db.Appointments.FindAsync(editingAppointment.Id);
        if (entity == null) return;

        var newStart = rescheduleTime.ToUniversalTime();
        var newEnd = newStart.AddMinutes((entity.EndTime - entity.StartTime).TotalMinutes);

        // Check conflicts
        var hasConflict = await db.Appointments.AnyAsync(a =>
            a.Id != entity.Id &&
            a.Status != AppointmentStatus.Cancelled &&
            a.Veterinarian == editingAppointment.Veterinarian &&
            a.StartTime < newEnd && a.EndTime > newStart);

        if (hasConflict)
        {
            rescheduleError = "This time slot conflicts with another appointment for the same veterinarian.";
            return;
        }

        entity.StartTime = newStart;
        entity.EndTime = newEnd;
        entity.Veterinarian = editingAppointment.Veterinarian;
        entity.Notes = editingAppointment.Notes;
        await db.SaveChangesAsync();

        editingAppointment = null;
        successMessage = "Appointment rescheduled.";
        await LoadAppointments();
    }

    private string StatusColor(AppointmentStatus s) => s switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.CheckedIn => "info",
        AppointmentStatus.InProgress => "warning",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        AppointmentStatus.NoShow => "danger",
        _ => "secondary"
    };
}

@page "/appointments/new"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
