                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Vaccination", 35)'>Vaccination — $35</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Blood Work", 75)'>Blood Work — $75</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("X-Ray", 120)'>X-Ray — $120</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Dental Cleaning", 200)'>Dental Cleaning — $200</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Surgery", 500)'>Surgery — $500</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Medication", 25)'>Medication — $25</button>
                </div>
            </div>
