{"file_text": "@page "/billing"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>Billing — VetClinic</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h1>🧾 Billing</h1>
    <button class="btn btn-primary" @onclick='() => Nav.NavigateTo("/billing/new-invoice")'>+ New Invoice</button>
</div>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item"><button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => { activeTab = "invoices"; }'>Invoices</button></li>
    <li class="nav-item"><button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => { activeTab = "payments"; LoadPayments(); }'>Payment History</button></li>
</ul>

@if (!string.IsNullOrEmpty(successMessage))
{
    <div class="alert alert-success alert-dismissible">@successMessage <button type="button" class="btn-close" @onclick="() => successMessage = null"></button></div>
}

@if (activeTab == "invoices")
{
    <div class="row mb-3">
        <div class="col-md-3">
            <select class="form-select" @bind="invoiceStatusFilter" @bind:after="LoadInvoices">
                <option value="">All statuses</option>
                @foreach (var s in Enum.GetValues<InvoiceStatus>())
                {
                    <option value="@s">@s</option>
                }
            </select>
        </div>
        <div class="col-md-3">
            <input type="text" class="form-control" placeholder="Search by invoice # or owner…" @bind="invoiceSearch" @bind:event="oninput" @bind:after="LoadInvoices" />
        </div>
    </div>

    <table class="table table-striped table-hover">
        <thead><tr><th>Invoice #</th><th>Date</th><th>Pet</th><th>Owner</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr></thead>
        <tbody>
        @foreach (var inv in invoices)
        {
            <tr>
                <td>@inv.InvoiceNumber</td>
                <td>@inv.IssuedDate.ToLocalTime().ToString("yyyy-MM-dd")</td>
                <td>@inv.Pet.Name</td>
                <td>@inv.Owner.FullName</td>
                <td>$@inv.Total.ToString("N2")</td>
                <td>$@inv.AmountPaid.ToString("N2")</td>
                <td class="@(inv.Balance > 0 ? "text-danger fw-bold" : "text-success")">$@inv.Balance.ToString("N2")</td>
                <td><span class="badge bg-@InvoiceStatusColor(inv.Status)">@inv.Status</span></td>
                <td>
                    <div class="btn-group btn-group-sm">
                        <button class="btn btn-outline-primary" @onclick="() => ViewInvoice(inv)">View</button>
                        @if (inv.Status == InvoiceStatus.Issued || inv.Status == InvoiceStatus.PartiallyPaid || inv.Status == InvoiceStatus.Overdue)
                        {
                            <button class="btn btn-outline-success" @onclick="() => StartPayment(inv)">Pay</button>
                        }
                    </div>
                </td>
            </tr>
        }
        </tbody>
    </table>
    if (invoices.Count == 0)
    {
        <div class="alert alert-info">No invoices found.</div>
    }
}
else
{
    <table class="table table-striped">
        <thead><tr><th>Date</th><th>Invoice #</th><th>Owner</th><th>Amount</th><th>Method</th><th>Status</th><th>Reference</th></tr></thead>
        <tbody>
        @foreach (var p in payments)
        {
            <tr>
                <td>@p.Date.ToLocalTime().ToString("yyyy-MM-dd h:mm tt")</td>
                <td>@p.Invoice.InvoiceNumber</td>
                <td>@p.Invoice.Owner.FullName</td>
                <td>$@p.Amount.ToString("N2")</td>
                <td>@p.Method</td>
                <td><span class="badge bg-@(p.Status == PaymentStatus.Completed ? "success" : p.Status == PaymentStatus.Refunded ? "warning" : "danger")">@p.Status</span></td>
                <td>@(p.Reference ?? "—")</td>
            </tr>
        }
        </tbody>
    </table>
    if (payments.Count == 0)
    {
        <div class="alert alert-info">No payment records.</div>
    }
}

@* View Invoice Modal *@
@if (viewingInvoice != null)
{
    <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog modal-lg">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Invoice @viewingInvoice.InvoiceNumber</h5>
                    <button type="button" class="btn-close" @onclick="() => viewingInvoice = null"></button>
                </div>
                <div class="modal-body">
                    <div class="row mb-3">
                        <div class="col-6"><strong>Pet:</strong> @viewingInvoice.Pet.Name<br/><strong>Owner:</strong> @viewingInvoice.Owner.FullName<br/><strong>Phone:</strong> @viewingInvoice.Owner.Phone</div>
                        <div class="col-6 text-end"><strong>Date:</strong> @viewingInvoice.IssuedDate.ToLocalTime().ToString("yyyy-MM-dd")<br/><strong>Status:</strong> <span class="badge bg-@InvoiceStatusColor(viewingInvoice.Status)">@viewingInvoice.Status</span></div>
                    </div>
                    <table class="table">
                        <thead><tr><th>Item</th><th class="text-end">Qty</th><th class="text-end">Unit Price</th><th class="text-end">Total</th></tr></thead>
                        <tbody>
                        @foreach (var item in viewingInvoice.Items)
                        {
                            <tr>
                                <td>@item.Description</td>
                                <td class="text-end">@item.Quantity</td>
                                <td class="text-end">$@item.UnitPrice.ToString("N2")</td>
                                <td class="text-end">$@item.LineTotal.ToString("N2")</td>
                            </tr>
                        }
                        </tbody>
                        <tfoot>
                            <tr class="fw-bold"><td colspan="3" class="text-end">Total:</td><td class="text-end">$@viewingInvoice.Total.ToString("N2")</td></tr>
                            <tr><td colspan="3" class="text-end">Paid:</td><td class="text-end">$@viewingInvoice.AmountPaid.ToString("N2")</td></tr>
                            <tr class="fw-bold"><td colspan="3" class="text-end">Balance:</td><td class="text-end text-@(viewingInvoice.Balance > 0 ? "danger" : "success")">$@viewingInvoice.Balance.ToString("N2")</td></tr>
                        </tfoot>
                    </table>
                    @if (!string.IsNullOrEmpty(viewingInvoice.Notes))
                    {
                        <p><strong>Notes:</strong> @viewingInvoice.Notes</p>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="() => viewingInvoice = null">Close</button>
                </div>
            </div>
        </div>
    </div>
}

@* Payment Modal *@
@if (payingInvoice != null)
{
    <div class="modal d-block" tabindex="-1" style="background: rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Process Payment — @payingInvoice.InvoiceNumber</h5>
                    <button type="button" class="btn-close" @onclick="() => payingInvoice = null"></button>
                </div>
                <div class="modal-body">
                    <p>Balance due: <strong class="text-danger">$@payingInvoice.Balance.ToString("N2")</strong></p>
                    <div class="mb-3">
                        <label class="form-label">Amount</label>
                        <input type="number" class="form-control" step="0.01" @bind="paymentAmount" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Payment Method</label>
                        <select class="form-select" @bind="paymentMethod">
                            @foreach (var m in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@m">@m</option>
                            }
                        </select>
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Reference</label>
                        <input type="text" class="form-control" @bind="paymentReference" placeholder="Card last 4, check #, etc." />
                    </div>
                    @if (!string.IsNullOrEmpty(paymentError))
                    {
                        <div class="alert alert-danger">@paymentError</div>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="() => payingInvoice = null">Cancel</button>
                    <button class="btn btn-success" @onclick="ProcessPayment">Process Payment</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private string invoiceStatusFilter = "";
    private string invoiceSearch = "";
    private List<Invoice> invoices = [];
    private List<Payment> payments = [];
    private Invoice? viewingInvoice;
    private Invoice? payingInvoice;
    private decimal paymentAmount;
    private PaymentMethod paymentMethod = PaymentMethod.Cash;
    private string? paymentReference;
    private string? paymentError;
    private string? successMessage;

    protected override async Task OnInitializedAsync() => await LoadInvoices();

    private async Task LoadInvoices()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var query = db.Invoices
            .Include(i => i.Pet)
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .AsQueryable();

        if (!string.IsNullOrWhiteSpace(invoiceStatusFilter) && Enum.TryParse<InvoiceStatus>(invoiceStatusFilter, out var status))
            query = query.Where(i => i.Status == status);
        if (!string.IsNullOrWhiteSpace(invoiceSearch))
        {
            var term = invoiceSearch.Trim().ToLower();
            query = query.Where(i => i.InvoiceNumber.ToLower().Contains(term)
                || i.Owner.FirstName.ToLower().Contains(term)
                || i.Owner.LastName.ToLower().Contains(term));
        }

        invoices = await query.OrderByDescending(i => i.IssuedDate).Take(100).ToListAsync();
    }

    private async Task LoadPayments()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        payments = await db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Owner)
            .OrderByDescending(p => p.Date)
            .Take(100)
            .ToListAsync();
    }

    private void ViewInvoice(Invoice inv) => viewingInvoice = inv;

    private void StartPayment(Invoice inv)
    {
        payingInvoice = inv;
        paymentAmount = inv.Balance;
        paymentMethod = PaymentMethod.Cash;
        paymentReference = null;
        paymentError = null;
    }

    private async Task ProcessPayment()
    {
        if (payingInvoice == null) return;
        if (paymentAmount <= 0)
        {
            paymentError = "Amount must be greater than zero.";
            return;
        }
        if (paymentAmount > payingInvoice.Balance)
        {
            paymentError = "Amount exceeds the outstanding balance.";
            return;
        }

        await using var db = await DbFactory.CreateDbContextAsync();
        var payment = new Payment
        {
            InvoiceId = payingInvoice.Id,
            Amount = paymentAmount,
            Method = paymentMethod,
            Reference = paymentReference,
            Date = DateTime.UtcNow,
            Status = PaymentStatus.Completed
        };
        db.Payments.Add(payment);

        var invoice = await db.Invoices.Include(i => i.Items).Include(i => i.Payments).FirstAsync(i => i.Id == payingInvoice.Id);
        // Reload to recalc after adding payment
        invoice.Payments.Add(payment);
        var newBalance = invoice.Total - invoice.Payments.Where(p => p.Status == PaymentStatus.Completed).Sum(p => p.Amount);
        invoice.Status = newBalance <= 0 ? InvoiceStatus.Paid : InvoiceStatus.PartiallyPaid;

        await db.SaveChangesAsync();
        payingInvoice = null;
        successMessage = $"Payment of ${paymentAmount:N2} processed successfully.";
        await LoadInvoices();
    }

    private string InvoiceStatusColor(InvoiceStatus s) => s switch
    {
        InvoiceStatus.Draft => "secondary",
        InvoiceStatus.Issued => "primary",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.PartiallyPaid => "warning",
        InvoiceStatus.Overdue => "danger",
        InvoiceStatus.Cancelled => "dark",
        _ => "secondary"
    };
}
