{"file_text": "@page "/billing/new-invoice"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>New Invoice — VetClinic</PageTitle>

<h1 class="mb-4">Create Invoice</h1>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row">
    <div class="col-md-8">
        <div class="card mb-3">
            <div class="card-header"><strong>Invoice Details</strong></div>
            <div class="card-body">
                <div class="row g-3 mb-3">
                    <div class="col-md-6">
                        <label class="form-label">Patient *</label>
                        <select class="form-select" @bind="selectedPetId" @bind:after="OnPetSelected">
                            <option value="0">Select a patient…</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Species) — @pet.Owner.FullName</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Due Date</label>
                        <input type="date" class="form-control" @bind="dueDate" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Status</label>
                        <select class="form-select" @bind="invoiceStatus">
                            <option value="@InvoiceStatus.Draft">Draft</option>
                            <option value="@InvoiceStatus.Issued">Issued</option>
                        </select>
                    </div>
                </div>
                <div class="mb-3">
                    <label class="form-label">Notes</label>
                    <textarea class="form-control" @bind="notes" rows="2"></textarea>
                </div>
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Line Items</strong>
                <button class="btn btn-sm btn-outline-primary" @onclick="AddLineItem">+ Add Item</button>
            </div>
            <div class="card-body p-0">
                <table class="table mb-0">
                    <thead><tr><th>Description</th><th style="width:100px">Qty</th><th style="width:130px">Unit Price</th><th style="width:120px">Total</th><th style="width:50px"></th></tr></thead>
                    <tbody>
                    @for (int i = 0; i < lineItems.Count; i++)
                    {
                        var idx = i;
                        <tr>
                            <td><input type="text" class="form-control form-control-sm" @bind="lineItems[idx].Description" placeholder="Service or product…" /></td>
                            <td><input type="number" class="form-control form-control-sm" min="1" @bind="lineItems[idx].Quantity" /></td>
                            <td><input type="number" class="form-control form-control-sm" step="0.01" @bind="lineItems[idx].UnitPrice" /></td>
                            <td class="text-end align-middle">$@((lineItems[idx].Quantity * lineItems[idx].UnitPrice).ToString("N2"))</td>
                            <td><button class="btn btn-sm btn-outline-danger" @onclick="() => lineItems.RemoveAt(idx)">✕</button></td>
                        </tr>
                    }
                    </tbody>
                    <tfoot>
                        <tr class="fw-bold">
                            <td colspan="3" class="text-end">Total:</td>
                            <td class="text-end">$@lineItems.Sum(i => i.Quantity * i.UnitPrice).ToString("N2")</td>
                            <td></td>
                        </tr>
                    </tfoot>
                </table>
            </div>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="CreateInvoice" disabled="@saving">@(saving ? "Creating…" : "Create Invoice")</button>
            <button class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("/billing")'>Cancel</button>
        </div>
    </div>

    <div class="col-md-4">
        @if (selectedOwner != null)
        {
            <div class="card">
                <div class="card-header"><strong>Owner Info</strong></div>
                <div class="card-body">
                    <p><strong>@selectedOwner.FullName</strong></p>
                    <p>📞 @selectedOwner.Phone</p>
                    @if (!string.IsNullOrEmpty(selectedOwner.Email))
                    {
                        <p>✉️ @selectedOwner.Email</p>
                    }
                    @if (!string.IsNullOrEmpty(selectedOwner.Address))
                    {
                        <p>📍 @selectedOwner.Address</p>
                    }
                </div>
            </div>
        }

        <div class="card mt-3">
            <div class="card-header"><strong>Common Services</strong></div>
            <div class="card-body">
                <div class="d-grid gap-1">
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Consultation", 50)'>Consultation — $50</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Vaccination", 35)'>Vaccination — $35</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Blood Work", 75)'>Blood Work — $75</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("X-Ray", 120)'>X-Ray — $120</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Dental Cleaning", 200)'>Dental Cleaning — $200</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Surgery", 500)'>Surgery — $500</button>
                    <button class="btn btn-sm btn-outline-secondary" @onclick='() => QuickAdd("Medication", 25)'>Medication — $25</button>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    private List<Pet> pets = [];
    private int selectedPetId;
    private Owner? selectedOwner;
    private DateOnly? dueDate;
    private InvoiceStatus invoiceStatus = InvoiceStatus.Draft;
    private string? notes;
    private List<LineItemModel> lineItems = [new()];
    private bool saving;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        dueDate = DateOnly.FromDateTime(DateTime.Today.AddDays(30));
    }

    private void OnPetSelected()
    {
        var pet = pets.FirstOrDefault(p => p.Id == selectedPetId);
        selectedOwner = pet?.Owner;
    }

    private void AddLineItem() => lineItems.Add(new());

    private void QuickAdd(string desc, decimal price)
    {
        lineItems.Add(new LineItemModel { Description = desc, Quantity = 1, UnitPrice = price });
    }

    private async Task CreateInvoice()
    {
        saving = true;
        errorMessage = null;
        try
        {
            if (selectedPetId == 0) { errorMessage = "Select a patient."; return; }
            if (lineItems.Count == 0 || lineItems.All(i => string.IsNullOrWhiteSpace(i.Description))) { errorMessage = "Add at least one line item."; return; }

            var pet = pets.First(p => p.Id == selectedPetId);

            await using var db = await DbFactory.CreateDbContextAsync();

            var count = await db.Invoices.CountAsync() + 1;
            var invoice = new Invoice
            {
                InvoiceNumber = $"INV-{count:D5}",
                PetId = selectedPetId,
                OwnerId = pet.OwnerId,
                IssuedDate = DateTime.UtcNow,
                DueDate = dueDate.HasValue ? dueDate.Value.ToDateTime(TimeOnly.MinValue) : null,
                Status = invoiceStatus,
                Notes = notes,
                Items = lineItems
                    .Where(i => !string.IsNullOrWhiteSpace(i.Description))
                    .Select(i => new InvoiceItem
                    {
                        Description = i.Description!,
                        Quantity = i.Quantity,
                        UnitPrice = i.UnitPrice
                    }).ToList()
            };

            db.Invoices.Add(invoice);
            await db.SaveChangesAsync();
            Nav.NavigateTo("/billing");
        }
        catch (Exception ex) { errorMessage = ex.Message; }
        finally { saving = false; }
    }

    private class LineItemModel
    {
        public string? Description { get; set; }
        public int Quantity { get; set; } = 1;
        public decimal UnitPrice { get; set; }
    }
}
