@page "/appointments/new"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@attribute [Authorize]
@inject IDbContextFactory<ApplicationDbContext> DbFactory
@inject NavigationManager Nav

<PageTitle>New Appointment — VetClinic</PageTitle>

<h1 class="mb-4">Schedule Appointment</h1>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row">
    <div class="col-md-7">
        <div class="card">
            <div class="card-body">
                <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="NewAppointment">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />

                    <div class="mb-3">
                        <label class="form-label">Patient *</label>
                        <select class="form-select" @bind="model.PetId" @bind:after="OnPetChanged">
                            <option value="0">Select a patient…</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Species) — Owner: @pet.Owner.FullName</option>
                            }
                        </select>
                    </div>

                    <div class="row g-3 mb-3">
                        <div class="col-md-6">
                            <label class="form-label">Date *</label>
                            <InputDate class="form-control" @bind-Value="model.Date" @bind-Value:after="CheckAvailability" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Time *</label>
                            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                                <option value="">Select a time…</option>
                                @foreach (var slot in availableSlots)
                                {
                                    <option value="@slot.ToString("HH:mm")">@slot.ToString("h:mm tt") @(bookedSlots.Contains(slot.ToString("HH:mm")) ? "⚠️ Busy" : "✅ Available")</option>
                                }
                            </InputSelect>
                        </div>
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Duration</label>
                        <InputSelect class="form-select" @bind-Value="model.DurationMinutes">
                            <option value="15">15 minutes</option>
                            <option value="30">30 minutes</option>
                            <option value="45">45 minutes</option>
                            <option value="60">60 minutes</option>
                        </InputSelect>
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Reason *</label>
                        <InputText class="form-control" @bind-Value="model.Reason" placeholder="e.g. Annual checkup, vaccination, dental cleaning…" />
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="model.Veterinarian" @bind-Value:after="CheckAvailability" />
                    </div>

                    <div class="mb-3">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="model.Notes" rows="2" />
                    </div>

                    <div class="d-flex gap-2">
                        <button type="submit" class="btn btn-primary" disabled="@saving">@(saving ? "Scheduling…" : "Schedule Appointment")</button>
                        <button type="button" class="btn btn-outline-secondary" @onclick='() => Nav.NavigateTo("/appointments")'>Cancel</button>
                    </div>
                </EditForm>
            </div>
        </div>
    </div>

    <div class="col-md-5">
        <div class="card">
            <div class="card-header"><strong>Availability for @model.Date.ToString("MMM dd, yyyy")</strong></div>
            <div class="card-body p-0">
                @if (dayAppointments.Count == 0)
                {
                    <p class="text-success p-3 mb-0">All time slots are available.</p>
                }
                else
                {
                    <table class="table table-sm mb-0">
                        <thead><tr><th>Time</th><th>Pet</th><th>Vet</th><th>Status</th></tr></thead>
                        <tbody>
                        @foreach (var apt in dayAppointments)
                        {
                            <tr>
                                <td>@apt.StartTime.ToLocalTime().ToString("h:mm tt") – @apt.EndTime.ToLocalTime().ToString("h:mm tt")</td>
                                <td>@apt.Pet.Name</td>
                                <td>@(apt.Veterinarian ?? "—")</td>
                                <td><span class="badge bg-@(apt.Status == AppointmentStatus.Cancelled ? "secondary" : "primary")">@apt.Status</span></td>
                            </tr>
                        }
                        </tbody>
                    </table>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [SupplyParameterFromQuery] public int? PetId { get; set; }

    private AppointmentFormModel model = new();
    private List<Pet> pets = [];
    private List<Appointment> dayAppointments = [];
    private List<DateTime> availableSlots = [];
    private HashSet<string> bookedSlots = [];
    private bool saving;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        pets = await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        model.Date = DateOnly.FromDateTime(DateTime.Today);
        model.DurationMinutes = 30;
        if (PetId.HasValue) model.PetId = PetId.Value;
        await CheckAvailability();
    }

    private async Task OnPetChanged() => await CheckAvailability();

    private async Task CheckAvailability()
    {
        await using var db = await DbFactory.CreateDbContextAsync();
        var date = model.Date.ToDateTime(TimeOnly.MinValue);
        var nextDate = date.AddDays(1);

        dayAppointments = await db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= date && a.StartTime < nextDate && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        // Generate slots from 8 AM to 6 PM
        availableSlots = [];
        bookedSlots = [];
        for (var hour = 8; hour < 18; hour++)
        {
            for (var min = 0; min < 60; min += 30)
            {
                var slot = new DateTime(date.Year, date.Month, date.Day, hour, min, 0);
                availableSlots.Add(slot);

                var slotEnd = slot.AddMinutes(model.DurationMinutes);
                var hasConflict = dayAppointments.Any(a =>
                    (string.IsNullOrEmpty(model.Veterinarian) || a.Veterinarian == model.Veterinarian) &&
                    a.StartTime.ToLocalTime() < slotEnd && a.EndTime.ToLocalTime() > slot);
                if (hasConflict)
                    bookedSlots.Add(slot.ToString("HH:mm"));
            }
        }
    }

    private async Task HandleSubmit()
    {
        saving = true;
        errorMessage = null;
        try
        {
            if (model.PetId == 0)
            {
                errorMessage = "Please select a patient.";
                return;
            }
            if (string.IsNullOrWhiteSpace(model.TimeSlot))
            {
                errorMessage = "Please select a time slot.";
                return;
            }

            var time = TimeOnly.Parse(model.TimeSlot);
            var startLocal = model.Date.ToDateTime(time);
            var startUtc = startLocal.ToUniversalTime();
            var endUtc = startUtc.AddMinutes(model.DurationMinutes);

            await using var db = await DbFactory.CreateDbContextAsync();

            // Final conflict check
            if (!string.IsNullOrWhiteSpace(model.Veterinarian))
            {
                var hasConflict = await db.Appointments.AnyAsync(a =>
                    a.Status != AppointmentStatus.Cancelled &&
                    a.Veterinarian == model.Veterinarian &&
                    a.StartTime < endUtc && a.EndTime > startUtc);
                if (hasConflict)
                {
                    errorMessage = "This time slot conflicts with another appointment for the selected veterinarian.";
                    return;
                }
            }

            var appointment = new Appointment
            {
                PetId = model.PetId,
                StartTime = startUtc,
                EndTime = endUtc,
                Reason = model.Reason!,
                Veterinarian = model.Veterinarian,
                Notes = model.Notes,
                Status = AppointmentStatus.Scheduled
            };

            db.Appointments.Add(appointment);
            await db.SaveChangesAsync();
            Nav.NavigateTo("/appointments");
        }
        catch (Exception ex)
        {
